INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
(1, '采灵芝', '到翠竹林采集3株灵芝，镇东药铺收。', 15, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 60, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵芝')), jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 10, 'max', 30)), 1, 20, false),
(1, '打野狼', '翠竹林最近野狼成患，去猎杀至少2头。', 20, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 15, 'max', 40)), 1, 15, false),
(1, '帮铁匠', '镇口铁匠需要5块玄铁矿石，去矿洞帮个忙。', 20, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 20, 'max', 50), jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='寒铁'))), 2, 18, false),
(1, '镇长的委托', '镇长家传玉佩掉进了井里，下去找回来（井底有蛇）。', 15, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='破风斩玉简'))), 1, 12, true),
(1, '巡逻翠竹林', '近日有修士在翠竹林失踪，去巡逻查看情况。', 25, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'spirit_stones', 'weight', 30, 'min', 25, 'max', 60), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵木'))), 1, 15, false),
(1, '新手试炼', '镇上的老修士想看看新人的实力，去矿洞里带一块石灵的结晶回来。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='清风剑法玉简')), jsonb_build_object('type', 'equipment', 'weight', 30, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='砍柴刀'))), 1, 10, true),
(1, '送信官道', '替镇口的驿卒送一封急信到云来村（虽说是急信但不急的话可以走官道）。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 60, 'min', 50, 'max', 120), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵木')), jsonb_build_object('type', 'rare_item', 'weight', 15, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='千年灵木'))), 3, 20, false),
(1, '夜巡坟岗', '镇上坟岗最近闹鬼，胆大的修士请去夜巡一番。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 60, 'max', 150), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨'))), 4, 10, false),
(1, '帮药铺采药', '药铺缺一批基础药材：灵芝、血参各3株。', 25, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 2, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵芝')), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='血参')), jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80)), 3, 15, false),
(1, '清理矿洞口', '矿洞口被塌方的碎石堵了，清理出来（顺带碰碰运气能不能挖到赤铜矿）。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 80, 'max', 200), jsonb_build_object('type', 'rare_item', 'weight', 35, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='赤铜矿')), jsonb_build_object('type', 'rare_item', 'weight', 15, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄铁矿石'))), 5, 18, false),
(1, '收集兽骨', '猎户需要一批兽骨制作工具，去矿洞周边找5根。', 20, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 10, 'max', 30)), 1, 18, false),
(1, '帮客栈跑堂', '客栈老板需要人帮忙搬货，顺便认识一下来往的客商。', 15, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 15, 'max', 40), jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮'))), 1, 18, false);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
(2, '采药修炼', '在竹林中采集灵草修炼基础心法，顺便给青石镇药铺供货。', 15, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 2, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵芝')), jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 15, 'max', 40)), 1, 25, false),
(2, '猎杀毒蛇', '林中毒蛇太多，已有村民被咬，猎杀5条毒蛇。', 20, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'spirit_stones', 'weight', 30, 'min', 20, 'max', 50), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨'))), 2, 20, false),
(2, '伐灵木', '砍伐10根灵木给镇里的木匠打造法器木胚。', 25, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 2, 'max', 4, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵木')), jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 25, 'max', 60), jsonb_build_object('type', 'rare_item', 'weight', 10, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄铁矿石'))), 2, 18, false),
(2, '采集月华露', '今天正好是月圆之夜，去竹林中采集月华露——注意避开夜间出没的妖兽。', 30, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 60, 'min', 1, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='月华露')), jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 50, 'max', 120)), 3, 12, false),
(2, '击杀野猪妖', '最近经常有野猪妖冲到青石镇啃庄稼，猎杀3头以儆效尤。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 60, 'max', 150), jsonb_build_object('type', 'rare_item', 'weight', 35, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮'))), 5, 15, false),
(2, '巡逻竹林', '有传言说竹林深处出现了一只石灵，去调查看看。', 30, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 45, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵木')), jsonb_build_object('type', 'spirit_stones', 'weight', 35, 'min', 40, 'max', 100), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄铁矿石'))), 3, 15, false),
(2, '猎杀狼群', '风狼族群扩张太快，威胁到了周围安全，至少猎杀4只。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 70, 'max', 180), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 2, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮'))), 6, 12, false),
(2, '寻找竹笋妖', '据说竹林中有一只竹笋成了精，把它抓回来（活的，别吃了）。', 25, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='青木诀玉简')), jsonb_build_object('type', 'beast_egg', 'weight', 25, 'name', '灵芝妖卵')), 4, 10, true),
(2, '帮猎户', '镇东猎户的猎犬走丢了，帮他在竹林里找回来。', 20, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 60, 'min', 30, 'max', 80), jsonb_build_object('type', 'rare_item', 'weight', 40, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮'))), 1, 15, false),
(2, '采集朱砂', '有人在山崖附近发现了品质不错的朱砂矿露头，去采一些回来。', 30, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 60, 'min', 2, 'max', 4, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂')), jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 30, 'max', 70)), 3, 15, false),
(2, '帮木匠', '镇东木匠要用灵木做一批家具，帮他砍够材料。', 20, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 2, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵木')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 20, 'max', 50)), 2, 20, false),
(2, '寻找失踪的药农', '有人声称在翠竹林深处看到了失踪药农的背篓。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='轻身术玉简'))), 3, 12, true);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
(3, '挖矿', '矿洞里挖10块玄铁矿石出来。', 20, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 2, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄铁矿石')), jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 20, 'max', 50), jsonb_build_object('type', 'rare_item', 'weight', 10, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='寒铁'))), 5, 25, false),
(3, '清理石灵', '矿洞深处出现了石灵阻路，清除3只以上。', 25, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 40, 'max', 100), jsonb_build_object('type', 'rare_item', 'weight', 35, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄铁矿石')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='赤铜矿'))), 5, 20, false),
(3, '寻找寒铁矿脉', '传闻矿洞深处有好品质的寒铁，去探查并带回至少3块。', 30, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='寒铁')), jsonb_build_object('type', 'spirit_stones', 'weight', 30, 'min', 50, 'max', 120), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄铁矿石'))), 7, 18, false),
(3, '矿洞探秘', '矿洞据说有三层，很少有人下到第三层。去那里看看有什么。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='蛮牛劲玉简'))), 8, 15, true),
(3, '灭鼠患', '妖鼠在矿洞里繁殖太快了，去清剿一批（至少8只）。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 50, 'max', 130), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 2, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮'))), 5, 15, false),
(3, '探索矿洞深处', '矿洞深处据说曾有青云门的洞府遗迹——虽然可能只是传说。', 45, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='金灵剑气玉简')), jsonb_build_object('type', 'equipment', 'weight', 20, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='桃木剑'))), 10, 12, true),
(3, '采矿竞赛', '玲珑坊悬赏：谁找到品质最高的寒铁谁得奖金。', 25, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 60, 'min', 60, 'max', 150), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='寒铁')), jsonb_build_object('type', 'rare_item', 'weight', 10, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='赤铜矿'))), 6, 15, false),
(3, '驱赶骷髅兵', '矿洞里最近出现了一些骷髅兵，似乎是死在矿洞里的矿工尸体被妖气复苏了。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 60, 'max', 150), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片'))), 8, 18, false),
(3, '寻找紫金砂', '紫金砂是炼制法器的重要辅料，去矿洞深处寻找至少2粒。', 40, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 60, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='紫金砂')), jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 80, 'max', 200)), 10, 12, false),
(3, '矿工失踪事件', '几个矿工在矿洞深处失踪了，下去找找看（做好遇到了不起怪物的心理准备）。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='霸刀诀玉简')), jsonb_build_object('type', 'beast_egg', 'weight', 25, 'name', '铁羽鹰卵')), 10, 10, true),
(3, '挖寒铁', '矿工说有片区域寒铁含量特别高，去试试。', 25, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='寒铁')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 50, 'max', 120)), 6, 20, false),
(3, '清除妖鼠', '矿工抱怨妖鼠咬坏了储物袋，去清理一下。', 20, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 40, 'max', 100), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄铁矿石'))), 5, 20, false);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
(4, '采冰魄花', '碧水潭底的千年冰晶上长出了冰魄花，想办法采一朵上来。', 25, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='冰魄花')), jsonb_build_object('type', 'spirit_stones', 'weight', 30, 'min', 30, 'max', 80), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='雪莲'))), 10, 20, false),
(4, '猎杀水鬼', '碧水潭有水鬼出没，已经有钓鱼的人被拖下水了。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 50, 'max', 120), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='月华露'))), 12, 18, false),
(4, '钓灵鱼', '碧水潭中的灵鱼肉质鲜美，据说吃了对修炼有好处。钓5条。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 40, 'max', 100), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵芝')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='血参'))), 10, 15, false),
(4, '采集水灵石', '潭底有沉积的水灵石，想办法采集至少5块。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 60, 'max', 150), jsonb_build_object('type', 'rare_item', 'weight', 35, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄晶')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='冰魄花'))), 12, 15, false),
(4, '调查妖兽异常', '碧水潭附近的妖兽最近异常躁动，去调查原因。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 70, 'max', 180), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨'))), 11, 12, false),
(4, '采集何首乌', '听说潭边的山壁上长了一株千年何首乌，去看看还在不在。', 40, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='何首乌')), jsonb_build_object('type', 'spirit_stones', 'weight', 30, 'min', 80, 'max', 200), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵芝'))), 12, 15, false),
(4, '清理食人花', '潭边的食人花越长越多，从枫叶坡那边蔓延过来了。', 25, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 40, 'max', 100), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='地火芝')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='太阳花'))), 10, 15, false),
