(4, '捕捉妖兽幼崽', '有人出灵石收购活的妖兽幼崽，去潭边碰碰运气。', 45, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 60, 'min', 120, 'max', 300), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'rare_item', 'weight', 15, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨'))), 14, 10, false),
(4, '潭底秘境', '有个渔夫说他曾在潭底看到过一扇石门，似乎是某个古代洞府的入口。', 60, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='寒冰掌玉简')), jsonb_build_object('type', 'beast_egg', 'weight', 25, 'name', '雪狐卵'), jsonb_build_object('type', 'equipment', 'weight', 25, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='亮银枪'))), 15, 8, true),
(4, '采集雪莲', '碧水潭边的雪峰上开了不少雪莲。', 30, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='雪莲')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 50, 'max', 120)), 11, 18, false),
(4, '帮渔夫收网', '一个渔夫年纪大了，帮他收一下网——当然网里的灵鱼分你几条。', 20, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 40, 'max', 100), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵芝')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='血参'))), 10, 18, false);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
(5, '采集地火芝', '枫叶坡的火脉附近长有地火芝，采集3朵。', 25, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='地火芝')), jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 30, 'max', 80)), 15, 20, false),
(5, '清理枫叶坡妖兽', '枫叶坡的妖兽最近特别多，可能是附近有什么情况。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 50, 'max', 120), jsonb_build_object('type', 'rare_item', 'weight', 35, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='血参'))), 15, 18, false),
(5, '探查废弃道观', '枫叶坡上那座废弃道观最近有怪声传出，去看看。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 60, 'max', 150), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片'))), 16, 15, false),
