(5, '寻找失踪商队', '一个商队在枫叶坡附近失踪了，去找找线索。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 100, 'max', 250), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵芝')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵蚕丝'))), 16, 15, false),
(5, '采集太阳花', '枫叶坡向阳的山坡上开了不少太阳花，采集5朵。', 25, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 60, 'min', 1, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='太阳花')), jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 30, 'max', 70)), 15, 18, false),
(5, '猎杀妖狐', '一只妖狐经常在枫叶坡出没，已迷惑了好几个路人。解决它。', 45, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 120, 'max', 300), jsonb_build_object('type', 'rare_item', 'weight', 35, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'equipment', 'weight', 25, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='兽皮甲'))), 18, 12, false),
(5, '采集灵蚕丝', '枫叶坡深处据说有灵桑树，去看看能不能采集一些灵蚕丝。', 35, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵蚕丝')), jsonb_build_object('type', 'spirit_stones', 'weight', 30, 'min', 40, 'max', 100), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵木'))), 15, 15, false),
(5, '夜探道观', '有人声称在废弃道观中看到了青云门的信物，去确认一下。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='静心诀玉简'))), 18, 8, true),
