(5, '帮道观修缮', '那座废弃道观如果有修士愿意简单修缮一下，附近的村民很感激。', 45, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 100, 'max', 250), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵木'))), 16, 12, false);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
(6, '采茶', '云来村以云雾茶闻名，帮忙采一筐茶送到古道驿站。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 40, 'max', 100), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵芝')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='血参'))), 18, 20, false),
(6, '寻找走失修士', '一个从青石镇来的年轻修士在云雾中走丢了——这种人每年都有。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 60, 'max', 150), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂'))), 18, 15, false),
(6, '猎杀妖兽', '云来村周围的山林中有妖兽出没，去清理至少5只。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 50, 'max', 120), jsonb_build_object('type', 'rare_item', 'weight', 35, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮'))), 18, 18, false),
(6, '护送商队', '一支商队要从云来村出发去飞云城，路上不太平。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 60, 'min', 100, 'max', 250), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂')), jsonb_build_object('type', 'rare_item', 'weight', 15, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='月华露'))), 20, 20, false),
(6, '采集云雾茶', '云来村的云雾茶产量不足，去悬崖上采集野生云雾茶。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 80, 'max', 200), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='血参')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='千年灵芝'))), 20, 12, false),
(6, '清理落日峰的山道', '落日峰上山道有塌方，去清出一条路。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 50, 'max', 120), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄铁矿石')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='紫丹参'))), 20, 15, false),
(6, '调查失踪村民', '云来村接连失踪了三个村民，有人说是山魈干的。查个水落石出。', 45, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='通明心法玉简')), jsonb_build_object('type', 'beast_egg', 'weight', 25, 'name', '灵猫卵'), jsonb_build_object('type', 'equipment', 'weight', 25, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='玄铁甲'))), 22, 10, true),
(6, '给茶寮备货', '帮茶寮的老板收集食材：3份灵芝、3份血参、2份何首乌。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 60, 'max', 150), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵芝')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='血参'))), 20, 15, false),
(6, '送信古道驿站', '村中老修士有一封信要送到古道驿站，顺道采购一些朱砂回来。', 60, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 60, 'min', 120, 'max', 300), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂')), jsonb_build_object('type', 'rare_item', 'weight', 15, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='月华露'))), 22, 20, false),
(6, '村中斗法', '村里来了一位外地的修士在挑衅，请一位本地修士去比试比试（友谊切磋）。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 100, 'max', 250), jsonb_build_object('type', 'equipment', 'weight', 30, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='青冥剑')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂'))), 22, 10, false),
(6, '帮村民修路', '云来村到落日峰的山路被冲断了一段，帮忙修好。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 80, 'max', 200), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵木')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄铁矿石'))), 20, 18, false),
(6, '采药换钱', '药铺说如果带够灵芝和血参，可以换更高价。', 30, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 2, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵芝')), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='血参')), jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 60, 'max', 150)), 20, 20, false);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
(7, '登顶落日峰', '登顶落日峰，在峰顶道观中打坐修炼一炷香，峰顶灵气浓郁对修炼大有裨益。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 80, 'max', 200), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='太阳花'))), 22, 25, false),
(7, '清理血蝠', '峰腰的洞穴中盘踞了大群血蝠，去清理至少10只。', 25, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 60, 'max', 150), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮'))), 22, 20, false),
