(7, '猎杀螳螂妖', '峰腰有一种螳螂妖特别凶猛，已有数人受伤，清剿5只。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 80, 'max', 200), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨'))), 24, 15, false),
(7, '采集紫丹参', '峰南面的山壁上有野生的紫丹参，采3株。', 25, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='紫丹参')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 50, 'max', 120)), 22, 15, false),
(7, '护送采药人', '一个采药老头想上峰采药但不敢一个人去，陪他一趟。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 100, 'max', 250), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='血参')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵芝'))), 24, 18, false),
(7, '峰顶秘境', '据说落日峰顶有一个云洞，跳进去可以去到一个隐秘空间——当然先确保自己会飞。', 60, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='焚天诀玉简')), jsonb_build_object('type', 'beast_egg', 'weight', 25, 'name', '火蟾卵'), jsonb_build_object('type', 'equipment', 'weight', 25, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='纯钧剑'))), 28, 8, true),
(7, '采集朱砂', '峰腰的山壁上朱砂品质不错。', 25, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 2, 'max', 4, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 60, 'max', 150)), 22, 20, false),
(7, '登高观日出', '据说在峰顶看日出能感悟一丝火之道韵。', 20, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 60, 'max', 150), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='太阳花')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂'))), 22, 15, false);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
(8, '采集幽冥花', '沼泽深处的幽冥花只在阴气浓重时开放，采两朵回来。', 30, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='幽冥花')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 80, 'max', 200)), 26, 18, false),
(8, '猎杀毒蟾', '沼泽里的毒蟾数量暴增，已影响到周边生态。清剿8只。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 80, 'max', 200), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片'))), 26, 20, false),
(8, '寻找失踪修士', '一位前往沼泽历练的修士许久未归，去把他找回来。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 120, 'max', 300), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='幽冥花'))), 28, 15, false),
(8, '采集还魂草', '沼泽的悬崖峭壁上长有还魂草，采1株就够——这东西太难找了。', 45, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 60, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='还魂草')), jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 150, 'max', 350)), 28, 12, false),
(8, '清理幽魂', '沼泽中幽魂越来越多，有向周边蔓延的趋势。至少消解10只。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 100, 'max', 250), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='曼陀罗'))), 28, 18, false),
(8, '沼泽深处探索', '有人说在沼泽最深处看到了远古神殿的废墟。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='万剑归宗玉简')), jsonb_build_object('type', 'beast_egg', 'weight', 25, 'name', '碧鳞蛇卵'), jsonb_build_object('type', 'equipment', 'weight', 25, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='灵蚕法袍'))), 30, 10, true),
(8, '采集曼陀罗', '沼泽中生长着剧毒的曼陀罗，但炼丹用得着。采2朵，戴好手套。', 30, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='曼陀罗')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 80, 'max', 200)), 28, 15, false),
(8, '消灭沼泽妖兽', '各种沼泽妖兽让采药队伍寸步难行，清理至少6只不同妖兽。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 100, 'max', 250), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮'))), 26, 18, false),
(8, '寻找失落的丹方', '传说有位金丹修士在沼泽中遇难，他的丹方可能还飘在沼泽某处。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='静心诀玉简'))), 30, 10, true),
(8, '采集妖兽毒囊', '沼泽毒兽的毒囊是制作高级丹药的材料，收集5个。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 100, 'max', 250), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片'))), 28, 15, false),
(8, '采集还魂草', '沼泽东部的还魂草据说年份特别足。', 40, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='还魂草')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 120, 'max', 300)), 28, 15, false),
(8, '帮采药队探路', '一支采药队想进沼泽采药但怕妖兽，你去踩点。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 120, 'max', 300), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='幽冥花'))), 27, 18, false);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
(9, '探索废墟', '青龙门遗址中有大量残垣断壁，每一处都可能藏着遗宝。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 120, 'max', 300), jsonb_build_object('type', 'rare_item', 'weight', 35, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='紫金砂'))), 28, 20, false),
(9, '驱散怨灵', '青龙门覆灭后留下的怨念化作了无数怨灵，超度至少5个。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 100, 'max', 250), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='月华露'))), 28, 18, false),
(9, '寻找青云秘典', '据说青云门有一部不传之秘典藏在遗址某处。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='诛仙剑诀玉简')), jsonb_build_object('type', 'equipment', 'weight', 25, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='灵蚕法袍'))), 30, 12, true),
(9, '收集遗物', '收集青云门散落的遗物：法器碎片、玉简残片、兵器残骸各2件。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 100, 'max', 250), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='紫金砂')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='寒铁'))), 28, 15, false),
(9, '消灭九尾妖狐', '遗址深处有一只九尾妖狐盘踞，修为不浅。小心应对。', 60, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 300, 'max', 700), jsonb_build_object('type', 'rare_item', 'weight', 35, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'equipment', 'weight', 25, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='纯钧剑'))), 32, 10, false),
(9, '采集魂玉碎片', '遗址中散落着大量魂玉碎片——注意不要被怨念侵蚀心神。', 30, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 60, 'min', 2, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 100, 'max', 250)), 28, 20, false),
(9, '探明月华密道', '据说月光照在遗址某处时会显现一条密道。去验证一下。', 45, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='轩辕剑法玉简'))), 30, 12, true),
(9, '清除妖兽', '遗址周围妖兽横行，猎杀至少8只。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 100, 'max', 250), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片'))), 28, 18, false),
(9, '寻找青云令牌', '青云门的掌门令牌据说还在遗址中，虽可能无用但有收藏价值。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='莲华涅槃玉简')), jsonb_build_object('type', 'beast_egg', 'weight', 25, 'name', '玉兔卵'), jsonb_build_object('type', 'equipment', 'weight', 25, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='金刚杵')), 32, 8, true),
(9, '午夜探险', '午夜子时进入遗址据说能看到青云门覆灭当晚的景象——胆小的别去。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='道心通明玉简'))), 32, 8, true),
(9, '研究废墟石刻', '遗址中的石刻似乎记载了青云门的独门心法。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 150, 'max', 350), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='紫金砂'))), 30, 15, false),
(9, '清除残存阵法', '遗址中有些防御阵法竟然还在运转，解除它们。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 150, 'max', 350), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='紫金砂')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='寒铁'))), 28, 15, false);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
(10, '修缮驿道', '古道的路面年久失修，帮忙填坑铺石。', 25, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 100, 'max', 250), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵木')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄铁矿石'))), 30, 20, false),
(10, '护送车队到飞云城', '一支商队要出发去飞云城，聘请修士护驾。', 60, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 55, 'min', 200, 'max', 500), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='紫金砂'))), 30, 25, false),
(10, '清理驿道旁妖兽', '驿道附近的妖兽经常袭击过往旅人，清理一下。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 120, 'max', 300), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片'))), 30, 18, false),
(10, '采购物资', '驿站需要一批丹药补给，跑腿去飞云城采购回来。', 90, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 55, 'min', 350, 'max', 800), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄晶'))), 30, 20, false),
(10, '寻人启事', '有人在驿站贴了寻人启事：他兄弟在迷雾沼泽失踪了。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='剑心通明玉简'))), 32, 15, true),
(10, '采集灵木', '驿站后的山林中有百年灵木，伐几根回来修缮驿站。', 30, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 50, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='千年灵木')), jsonb_build_object('type', 'spirit_stones', 'weight', 30, 'min', 100, 'max', 250), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='灵木'))), 30, 18, false),
(10, '驱赶盗贼', '最近有伙盗贼专门在驿道上打劫，给他们点教训。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 150, 'max', 350), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='赤铜矿')), jsonb_build_object('type', 'equipment', 'weight', 25, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='玄铁甲'))), 32, 15, false),
(10, '送急报', '驿站收到一封急报要送到玲珑坊，快马加鞭（御剑更快）。', 120, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 55, 'min', 500, 'max', 1200), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='紫金砂')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片'))), 30, 20, false),
(10, '寻找灵兽坐骑', '有人重金悬赏活的飞行妖兽幼崽当坐骑。', 90, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 350, 'max', 800), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'beast_egg', 'weight', 25, 'name', '铁羽鹰卵')), 34, 10, false),
(10, '打扫战场', '之前有修士在驿道附近大战妖兽，去清理战场——顺便捡捡漏。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 120, 'max', 300), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片'))), 30, 18, false),
(10, '收集千年灵木', '驿道旁的古树林中有几棵千年灵木可以采。', 35, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='千年灵木')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 120, 'max', 300)), 32, 18, false),
(10, '替商队探路', '有商队想知道前方路况——去侦察一下。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 150, 'max', 350), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片'))), 31, 18, false);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
(11, '送货上门', '飞云城某店铺需要一批玄铁矿石，从青石矿洞运来。', 60, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 55, 'min', 200, 'max', 500), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄铁矿石')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='寒铁'))), 35, 20, false),
(11, '城中巡查', '飞云城的守卫人手不足，临时雇修士巡查街坊。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 120, 'max', 300), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮'))), 35, 18, false),
(11, '帮法宝阁收材料', '法宝阁急需一批紫金砂和魂玉碎片。', 45, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 150, 'max', 350), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='紫金砂')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片'))), 35, 15, false),
(11, '斗法擂台', '飞云城每月一次的斗法擂台开赛了，去打一场（不论输赢都有奖励）。', 30, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 200, 'max', 500), jsonb_build_object('type', 'equipment', 'weight', 30, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='青冥剑')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂'))), 38, 20, false),
(11, '护送炼丹材料', '丹坊有一批珍贵药材要运到天剑宗遗址附近交接。', 75, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 55, 'min', 300, 'max', 700), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='血参')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='何首乌'))), 38, 18, false),
(11, '抓捕小偷', '一个小偷专偷法宝阁的矿石材料，把他揪出来。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='鹰眼术玉简'))), 36, 12, true),
(11, '研究万兽山地图', '有位老修士需要一份最新绘制的万兽山地图，跑一趟。', 120, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='奇门遁甲玉简'))), 38, 15, true),
(11, '帮灵兽铺找蛋', '灵兽铺的灵兽最近不下蛋了，去万兽山找几个新鲜的妖兽卵回来。', 60, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 200, 'max', 500), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'beast_egg', 'weight', 25, 'name', '灵猫卵')), 40, 12, false),
(11, '收集情报', '最近北方似乎有什么异动，去万兽山那边打探一下消息。', 80, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 300, 'max', 700), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='紫金砂'))), 40, 15, false),
(11, '捐赠灵石建庙', '飞云城要建一座新的土地庙，出钱出力都可以。', 20, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 150, 'max', 350), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='朱砂')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='何首乌'))), 35, 10, false),
(11, '帮丹坊收购药材', '丹坊要收购一批血参和何首乌，跑腿去枫叶坡买回来。', 60, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 55, 'min', 200, 'max', 500), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='血参')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='何首乌'))), 36, 18, false),
(11, '帮器阁整理库存', '器阁的仓库乱得像被妖兽翻过一样，帮忙整理。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 150, 'max', 350), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='玄铁矿石')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='寒铁'))), 35, 15, false);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
(12, '猎杀猿妖', '万兽山中的猿妖霸占了一条山路，猎杀3只清理通道。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 150, 'max', 350), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮'))), 38, 20, false),
(12, '采集兽骨', '满山的妖兽尸骨，收集10份质量好的兽骨回来。', 30, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 2, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 120, 'max', 300)), 38, 25, false),
(12, '猎杀狮鹫', '空中盘旋的狮鹫让巡山弟子头疼不已，射下来2只。', 45, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 200, 'max', 500), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'equipment', 'weight', 25, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='穿云弓'))), 42, 15, false),
(12, '寻找妖兽巢穴', '深入万兽山绘制最新的妖兽巢穴分布图。', 60, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 400, 'max', 1000), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='蛮牛劲玉简')), jsonb_build_object('type', 'beast_egg', 'weight', 25, 'name', '虎蛟卵')), 42, 15, true),
(12, '采集龙血草', '有传言说万兽山深处有龙气浸润之地，可能长着龙血草。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='龙血草'))), 44, 10, true),
