(12, '捕捉妖兽幼崽', '飞云城灵兽铺要补货了，抓5只活的妖兽幼崽。', 45, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 200, 'max', 500), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'beast_egg', 'weight', 25, 'name', '灵猫卵')), 40, 12, false),
(12, '清理妖兽巢穴', '发现了一处妖兽巢穴，清理干净避免繁殖扩散。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 200, 'max', 500), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片'))), 40, 18, false),
(12, '猎杀巨蟒', '一条巨蟒在进山必经之路上做窝，清理掉。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 200, 'max', 500), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮')), jsonb_build_object('type', 'equipment', 'weight', 25, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='银丝软鞭'))), 40, 18, false),
(12, '采集血参', '山林深处有野生的血参，采5株回来。', 30, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 2, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='血参')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 150, 'max', 350)), 38, 18, false),
(12, '帮猎人追踪', '一群猎人追踪一只稀有妖兽追了好几里了，帮他们一把。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 250, 'max', 600), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='妖兽皮'))), 40, 15, false),
(12, '探索古兽道', '万兽山有一条被遗忘的古兽道，据说是远古妖兽迁徙留下的痕迹。', 70, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 40, 'min', 400, 'max', 1000), jsonb_build_object('type', 'rare_item', 'weight', 35, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='龙血草')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='兽骨'))), 44, 10, false);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
(13, '采集幽冥花', '幽冥谷中的幽冥花比沼泽的品质高得多，采3朵。', 35, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 2, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='幽冥花')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 150, 'max', 350)), 42, 20, false),
(13, '超度亡魂', '幽冥谷中亡魂多到影响阳间秩序了，超度至少10个。', 40, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 150, 'max', 350), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 2, 'max', 3, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='幽冥花'))), 42, 18, false),
(13, '采集太阴菇', '谷中阴气浓重处生有太阴菇，是炼制阴丹的好材料。', 30, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='太阴菇')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 150, 'max', 350)), 42, 15, false),
(13, '寻找失落的魂玉', '据说一位合体期大修士在幽冥谷陨落，他的魂玉还在谷中。', 60, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='伏魔棍玉简')), jsonb_build_object('type', 'beast_egg', 'weight', 25, 'name', '碧鳞蛇卵'), jsonb_build_object('type', 'equipment', 'weight', 25, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='七星剑'))), 45, 10, true),
(13, '调查结界裂缝', '幽冥谷深处有一处通向阳间的结界裂缝似乎在扩大。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 20, 'min', 30, 'max', 80), jsonb_build_object('type', 'skill_jade', 'weight', 30, 'template_id', (SELECT id FROM xt_item_template WHERE name='镇魂钟声玉简'))), 45, 12, true),
(13, '消灭夜叉', '从冥界跑出来的夜叉盘踞在谷中，清除之。', 50, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 250, 'max', 600), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'equipment', 'weight', 25, 'template_id', (SELECT id FROM xt_equipment_template WHERE name='镇魂铃'))), 46, 15, false),
