(13, '寻找失踪同门', '一个宗门弟子在幽冥谷历练时失联了，找回来。', 45, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 200, 'max', 500), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='幽冥花'))), 44, 12, false),
(13, '净化阴气', '幽冥谷外围的阴气已经开始影响周围村庄了，用法力驱散。', 45, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 200, 'max', 500), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='太阴菇'))), 42, 18, false),
(13, '收集太阴菇孢子', '不仅采摘，还要收集孢子以备种植——这是可持续采集的要求。', 35, jsonb_build_array(jsonb_build_object('type', 'rare_item', 'weight', 55, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='太阴菇')), jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 200, 'max', 500)), 42, 15, false),
(13, '协助封印', '幽冥谷深处有一处冥界裂缝需要加固封印。', 55, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 45, 'min', 300, 'max', 700), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='紫金砂')), jsonb_build_object('type', 'rare_item', 'weight', 25, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片'))), 44, 15, false),
(13, '猎杀幽魂', '阴气太重的地方自然滋生幽魂，消解一批。', 35, jsonb_build_array(jsonb_build_object('type', 'spirit_stones', 'weight', 50, 'min', 200, 'max', 500), jsonb_build_object('type', 'rare_item', 'weight', 30, 'min', 1, 'max', 2, 'template_id', (SELECT id FROM xt_item_template WHERE name='魂玉碎片')), jsonb_build_object('type', 'rare_item', 'weight', 20, 'min', 1, 'max', 1, 'template_id', (SELECT id FROM xt_item_template WHERE name='幽冥花'))), 42, 18, false);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight, is_unique) VALUES
